import { defineContract } from 'aether';

export default defineContract({
  name: 'teams',
  description: 'Manages teams, team members, and team-related settings.',

  dependencies: {
    modules: ['auth'],
  },

  exposes: {
    routes: [
      { method: 'POST',   path: '/teams',                  auth: true },
      { method: 'GET',    path: '/teams/:teamId',          auth: true },
      { method: 'PUT',    path: '/teams/:teamId',          auth: true },
      { method: 'DELETE', path: '/teams/:teamId',          auth: true },
      { method: 'GET',    path: '/teams/:teamId/members',  auth: true },
      { method: 'POST',   path: '/teams/:teamId/members',  auth: true },
      { method: 'DELETE', path: '/teams/:teamId/members/:userId', auth: true }, // New route
    ],
    functions: [
      'createTeam',
      'getTeamById',
      'updateTeam',
      'deleteTeam',
      'addTeamMember',
      'getTeamMembers',
      'isTeamOwner',
      'isTeamMember',
    ],
    types: ['Team', 'TeamMember', 'TeamRole'],
  },

  sideEffects: [
    'writes to: teams table',
    'writes to: team_members table',
    'reads from: users table',
    'reads from: tasks table', // Added for unassigning tasks
    'writes to: tasks table',  // Added for unassigning tasks
  ],

  invariants: [
    'A team must always have exactly one owner',
    'A user can only be a member of a team once',
    'Deleting a team must also delete all its members and associated tasks',
    'Removing a member must unassign their tasks within that team', // New invariant
  ],
});
