import { query, transaction } from 'lib/db';
import { User } from 'modules/auth/module.contract'; // Assuming User type is exposed by auth module

export async function createTeamQuery(name: string, ownerId: string) {
  return query<{ id: string; name: string; owner_id: string }>(
    `INSERT INTO teams (name, owner_id) VALUES ($1, $2) RETURNING id, name, owner_id`,
    [name, ownerId]
  );
}

export async function addTeamMemberQuery(teamId: string, userId: string, role: string) {
  return query<{ team_id: string; user_id: string; role: string }>(
    `INSERT INTO team_members (team_id, user_id, role) VALUES ($1, $2, $3) RETURNING team_id, user_id, role`,
    [teamId, userId, role]
  );
}

export async function getTeamByIdQuery(teamId: string) {
  return query<{ id: string; name: string; owner_id: string }>(
    `SELECT id, name, owner_id FROM teams WHERE id = $1`,
    [teamId]
  );
}

export async function getTeamMembersQuery(teamId: string) {
  return query<User & { role: string }>(
    `SELECT u.id, u.email, u.name, tm.role
     FROM team_members tm
     JOIN users u ON tm.user_id = u.id
     WHERE tm.team_id = $1`,
    [teamId]
  );
}

export async function isTeamOwnerQuery(teamId: string, userId: string) {
  const result = await query<{ exists: boolean }>(
    `SELECT EXISTS(SELECT 1 FROM teams WHERE id = $1 AND owner_id = $2) AS exists`,
    [teamId, userId]
  );
  return result[0]?.exists || false;
}

export async function isTeamMemberQuery(teamId: string, userId: string) {
  const result = await query<{ exists: boolean }>(
    `SELECT EXISTS(SELECT 1 FROM team_members WHERE team_id = $1 AND user_id = $2) AS exists`,
    [teamId, userId]
  );
  return result[0]?.exists || false;
}

export async function removeTeamMemberQuery(teamId: string, userId: string) {
  return query(
    `DELETE FROM team_members WHERE team_id = $1 AND user_id = $2`,
    [teamId, userId]
  );
}

export async function unassignTasksFromMemberInTeamQuery(teamId: string, userId: string) {
  return query(
    `UPDATE tasks SET assigned_to_user_id = NULL WHERE team_id = $1 AND assigned_to_user_id = $2`,
    [teamId, userId]
  );
}
