import { transaction } from 'lib/db';
import { ok, err, Result } from 'lib/result';
import {
  isTeamOwnerQuery,
  isTeamMemberQuery,
  removeTeamMemberQuery,
  unassignTasksFromMemberInTeamQuery,
} from 'modules/teams/lib/queries';

type RemoveMemberError = 'NOT_FOUND' | 'NOT_AUTHORIZED' | 'CANNOT_REMOVE_OWNER' | 'UNKNOWN_ERROR';

export async function removeMemberFromTeam(
  teamId: string,
  memberId: string,
  requestingUserId: string
): Promise<Result<void, RemoveMemberError>> {
  return transaction(async (db) => {
    // 1. Verify requesting user is the team owner
    const isOwner = await isTeamOwnerQuery(teamId, requestingUserId);
    if (!isOwner) {
      return err('NOT_AUTHORIZED');
    }

    // 2. Verify the member to be removed exists in the team
    const isMember = await isTeamMemberQuery(teamId, memberId);
    if (!isMember) {
      return err('NOT_FOUND');
    }

    // 3. Prevent removing the team owner
    const isMemberOwner = await isTeamOwnerQuery(teamId, memberId);
    if (isMemberOwner) {
      return err('CANNOT_REMOVE_OWNER');
    }

    // 4. Remove the member from the team
    await removeTeamMemberQuery(teamId, memberId);

    // 5. Unassign all tasks assigned to this user within this team
    await unassignTasksFromMemberInTeamQuery(teamId, memberId);

    return ok(undefined);
  });
}
