import { Request, Response } from 'aether';
import { requireUser } from 'lib/auth';
import { parseParams } from 'lib/validate';
import { z } from 'zod';
import { removeMemberFromTeam } from 'modules/teams/services/remove-member';

const removeMemberParamsSchema = z.object({
  teamId: z.string().uuid('Invalid team ID format.'),
  userId: z.string().uuid('Invalid user ID format.'),
});

export async function removeMemberHandler(req: Request): Promise<Response> {
  const user = await requireUser(req); // Ensure user is authenticated

  const paramsResult = parseParams(req, removeMemberParamsSchema);
  if (paramsResult.isErr()) {
    return new Response(JSON.stringify({ error: paramsResult.error.message }), { status: 400, headers: { 'Content-Type': 'application/json' } });
  }
  const { teamId, userId } = paramsResult.value;

  const result = await removeMemberFromTeam(teamId, userId, user.id);

  if (result.isErr()) {
    switch (result.error) {
      case 'NOT_FOUND':
        return new Response(JSON.stringify({ error: 'Team or member not found.' }), { status: 404, headers: { 'Content-Type': 'application/json' } });
      case 'NOT_AUTHORIZED':
        return new Response(JSON.stringify({ error: 'You are not authorized to remove members from this team.' }), { status: 403, headers: { 'Content-Type': 'application/json' } });
      case 'CANNOT_REMOVE_OWNER':
        return new Response(JSON.stringify({ error: 'The team owner cannot be removed.' }), { status: 400, headers: { 'Content-Type': 'application/json' } });
      case 'UNKNOWN_ERROR':
      default:
        return new Response(JSON.stringify({ error: 'An unexpected error occurred.' }), { status: 500, headers: { 'Content-Type': 'application/json' } });
    }
  }

  return new Response(null, { status: 204 }); // No Content on successful deletion
}
